import{_ as a}from"./chunks/gongan.Co6hjsaP.js";import{_ as t,o,c as r,ae as e}from"./chunks/framework.Bn0jkBmj.js";const g=JSON.parse('{"title":"我们在母婴护理服务过程中碰到的经典案例","description":"不仅仅包括安抚婴儿哭声，还包括母乳喂养、黄疸、尿布疹、婴儿被动操、宝宝飞机抱、胎教、宝宝大动作精细动作发展等等","frontmatter":{"layout":"doc","title":"我们在母婴护理服务过程中碰到的经典案例","description":"不仅仅包括安抚婴儿哭声，还包括母乳喂养、黄疸、尿布疹、婴儿被动操、宝宝飞机抱、胎教、宝宝大动作精细动作发展等等"},"headers":[],"relativePath":"scl.md","filePath":"scl.md"}'),n={name:"scl.md"};function i(s,p,l,c,d,v){return o(),r("div",null,[...p[0]||(p[0]=[e('<h1 id="写在前面" tabindex="-1"><span style="font-size:14px;color:var(--vp-c-brand);margin-top:9px;">写在前面</span> <a class="header-anchor" href="#写在前面" aria-label="Permalink to &quot;&lt;span style=&quot;font-size: 14px; color: var(--vp-c-brand); margin-top: 9px;&quot;&gt;写在前面&lt;/span&gt;&quot;">​</a></h1><p>我们会把用户使用的反馈、咨询我们的专业问题、在家政服务过程中碰到的新鲜事等等，不定时发布于此。</p><h2 id="老婆发现-我手机收藏6000多" tabindex="-1"><span style="font-size:14px;color:var(--vp-c-brand);margin-top:9px;">老婆发现，我手机收藏6000多…</span> <a class="header-anchor" href="#老婆发现-我手机收藏6000多" aria-label="Permalink to &quot;&lt;span style=&quot;font-size: 14px; color: var(--vp-c-brand); margin-top: 9px;&quot;&gt;老婆发现，我手机收藏6000多…&lt;/span&gt;&quot;">​</a></h2><p>去年，临近元旦的一个晚上， 终于敲打出来了—— 宝宝哭声翻译器的雏形。</p><p>我抓起手机，第一次正式测试。</p><p>糟糕，怎么是报错⚠ 再测<s>报错⚠ 反复几次</s>始终报错⚠</p><p>我心里一颤：没道理啊？</p><p>翻来覆去，检查到半夜， 才发现，所有后端数据， 被纯小白的我， 不经意间，放到了国外服务器。</p><p>所以，国内的手机， 打不开这款工具。</p><p>这，就意味着—— 当我准备入住新房时，才突然发现： 刚刚装修完的，是别人家， 自己的毛坯房，在隔壁。</p><p>当时，脑袋一片空白🤯， 手心渗出细汗，却浑身寒意；</p><p>我推开记录本、关掉电脑、熄了台灯， 蜷缩在藤椅里。</p><p>冰冷的冬雨，拍着玻璃窗， 满脑尽是，报错的“黄色三角”。</p><p>闭上眼睛，又想着——</p><p>敲出的3000行代码、 编写的130页备忘录、 翻烂的2本教材……</p><p>似乎都在笑话 我这个野生码农。</p><p>现在…怎么办❓ 就此放弃？淘宝外包？从零开始？</p><p>连着几天， 整个人恍恍惚惚、话也少了。</p><p>一天晚餐后，老婆收拾碗筷时， 调侃我：最近更年期了吗？</p><p>当她知道原委后， 竟没心没肺地逗我： “反正就在隔壁，那就蚂蚁搬家呗”🐜</p><p>正要反驳她：搬家、不是、复制粘贴， 微信弹出提示—— 收到一段，月嫂新录的宝宝哭声。</p><p>坐在干净的餐桌前， 我轻轻地、划看6000多段录音， 偶尔点开一段听听。</p><p>每段背后，都有一个平凡的故事， 每段里面，都暗藏破解哭声的密码，</p><p>他们在我手机里， 静静地，等了5年；</p><p>再等5年吗？我都退休了……</p><p>那晚，听了很久很久的录音， 我重新坐回、21吋的大屏幕前🖥️。</p><p>看了看窗外的银行霓虹灯， 硬着头皮，点开了“阿里云&quot;……</p><p>全部完成“蚂蚁搬家”的那天， 我推开窗， 风中已没有了寒意，</p><p>南昌，已经进入 春暖花开的3月份了。</p><p>接着，放到小群测试， 竟收到老客户们、近百条反馈，</p><p>现在，我的“婴语翻译”工具， 不仅脱胎换骨， 而且完成了雏形的蜕变。</p><h2 id="文章2" tabindex="-1"><span style="font-size:14px;color:var(--vp-c-brand);margin-top:9px;">文章2</span> <a class="header-anchor" href="#文章2" aria-label="Permalink to &quot;&lt;span style=&quot;font-size: 14px; color: var(--vp-c-brand); margin-top: 9px;&quot;&gt;文章2&lt;/span&gt;&quot;">​</a></h2><p>（待发布）</p><h2 id="文章3" tabindex="-1"><span style="font-size:14px;color:var(--vp-c-brand);margin-top:9px;">文章3</span> <a class="header-anchor" href="#文章3" aria-label="Permalink to &quot;&lt;span style=&quot;font-size: 14px; color: var(--vp-c-brand); margin-top: 9px;&quot;&gt;文章3&lt;/span&gt;&quot;">​</a></h2><p>（待发布）</p><h2 id="文章4" tabindex="-1"><span style="font-size:14px;color:var(--vp-c-brand);margin-top:9px;">文章4</span> <a class="header-anchor" href="#文章4" aria-label="Permalink to &quot;&lt;span style=&quot;font-size: 14px; color: var(--vp-c-brand); margin-top: 9px;&quot;&gt;文章4&lt;/span&gt;&quot;">​</a></h2><p>（待发布）</p><h2 id="文章5" tabindex="-1"><span style="font-size:14px;color:var(--vp-c-brand);margin-top:9px;">文章5</span> <a class="header-anchor" href="#文章5" aria-label="Permalink to &quot;&lt;span style=&quot;font-size: 14px; color: var(--vp-c-brand); margin-top: 9px;&quot;&gt;文章5&lt;/span&gt;&quot;">​</a></h2><p>（待发布）</p><hr><p><br><br><br></p><div style="border-top:1px solid var(--vp-c-divider);padding:12px 0;text-align:center;font-size:8px;line-height:2;color:var(--vp-c-text-2);margin-top:40px;width:100%;"><div> ICP备案号： <a href="https://beian.miit.gov.cn" target="_blank" rel="noopener" style="color:var(--vp-c-brand);text-decoration:none;">ICP2025073122</a></div><div><img src="'+a+'" alt="警徽" style="width:14px;height:14px;vertical-align:-2px;margin-right:4px;display:inline-block;"> 网站联网备案号： <a href="https://beian.mps.gov.cn" target="_blank" rel="noopener" style="color:var(--vp-c-brand);text-decoration:none;">赣公网安备36010202000837号</a></div><div style="margin-top:4px;">Copyright © 2025 南昌市东湖区金宝贝职业月嫂中心</div></div>',42)])])}const m=t(n,[["render",i]]);export{g as __pageData,m as default};
